/**
 * @summary Get daily calorie and macro summary
 */
export const getGetDailySummaryUrl = (params?: GetDailySummaryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/daily-summary?${stringifiedParams}`
    : `/api/daily-summary`;
};

export const getDailySummary = async (
  params?: GetDailySummaryParams,
  options?: RequestInit,
): Promise<DailySummary> => {
  return customFetch<DailySummary>(getGetDailySummaryUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetDailySummaryQueryKey = (params?: GetDailySummaryParams) => {
  return [`/api/daily-summary`, ...(params ? [params] : [])] as const;
};

export const getGetDailySummaryQueryOptions = <
  TData = Awaited<ReturnType<typeof getDailySummary>>,
  TError = ErrorType<unknown>,
>(
  params?: GetDailySummaryParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getDailySummary>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetDailySummaryQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getDailySummary>>> = ({
    signal,
  }) => getDailySummary(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getDailySummary>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetDailySummaryQueryResult = NonNullable<
  Awaited<ReturnType<typeof getDailySummary>>
>;
export type GetDailySummaryQueryError = ErrorType<unknown>;

/**
 * @summary Get daily calorie and macro summary
 */

export function useGetDailySummary<
  TData = Awaited<ReturnType<typeof getDailySummary>>,
  TError = ErrorType<unknown>,
>(
  params?: GetDailySummaryParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getDailySummary>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetDailySummaryQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
